import pytest
import requests

BASE_URL = "http://localhost:8080"

@pytest.fixture
def auth_headers():
    return <get_auth_headers_fixture>

@pytest.fixture
def overdraft_account_sufficient_savings(auth_headers):
    return <setup_account_fixture>(
        checking_balance=10.00,
        savings_balance=500.00,
        overdraft_linked=True,
        auth_headers=auth_headers
    )

def test_overdraft_draws_from_savings_and_assesses_fee(auth_headers, overdraft_account_sufficient_savings):
    account_id = overdraft_account_sufficient_savings["account_id"]
    payload = {"account_id": account_id, "debit_amount": 150.00}

    resp = requests.post(
        f"{BASE_URL}/overdraft",
        json=payload,
        headers=auth_headers
    )

    assert resp.status_code == 200
    body = resp.json()
    assert body["status"] == "approved"
    assert body["savings_debited"] == pytest.approx(140.00, abs=0.01)
    assert body["overdraft_fee"] > 0
    assert "transaction_id" in body
    <teardown_account_fixture>(account_id, auth_headers)

