import pytest
import requests

BASE_URL = "http://localhost:8080"

INVALID_HEADERS = {"Authorization": "Bearer INVALID_TOKEN_XYZ"}

@pytest.fixture
def auth_headers():
    return <get_auth_headers_fixture>

@pytest.fixture
def any_overdraft_account(auth_headers):
    return <setup_account_fixture>(
        checking_balance=10.00,
        savings_balance=200.00,
        overdraft_linked=True,
        auth_headers=auth_headers
    )

def test_overdraft_rejected_without_valid_auth(auth_headers, any_overdraft_account):
    account_id = any_overdraft_account["account_id"]
    payload = {"account_id": account_id, "debit_amount": 50.00}

    resp = requests.post(
        f"{BASE_URL}/overdraft",
        json=payload,
        headers=INVALID_HEADERS
    )

    assert resp.status_code == 401
    body = resp.json()
    assert body.get("error") == "unauthorized"
    balance_after = <get_savings_balance_fn>(account_id, auth_headers)
    assert balance_after == pytest.approx(200.00, abs=0.01)
    <teardown_account_fixture>(account_id, auth_headers)

